package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testGetName() throws Exception {
    String expectedName = "Test Item";

    // Use reflection to get the constructor since LineItem is public but constructor is not fully shown
    var constructor = LineItem.class.getConstructor(String.class, int.class, long.class, String.class);
    LineItem lineItem = constructor.newInstance(expectedName, 5, 1000L, "USD");

    String actualName = lineItem.getName();
    assertEquals(expectedName, actualName);
  }
}
